  ('pukao-acfc4025-moex-00009', 'pukao-acfc4025', 'pukao-acfc4025-moex-114-156cbda0', 'sub-pukao-acfc4025-01', NULL, 'single_choice', '遞歸神經網路（RecurrentNeuralNetwork;RNN）是一種具有記憶功能的網路，常被應用於處理時間序列或 是自然語言處理問題，下列何者不屬於RNN的重要架構？', '["最大池化（MaximumPooling）", "長短期記憶（LongShort-TermMemory;LSTM）", "門控循環單元（GatedRecurrentUnit;GRU）", "控制閥（Gate）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:39+00:00", "source_pdf_sha1": "ebba180acb37", "answer_pdf_sha1": "b58c95b8bfaa", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "446", "s": "2504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "計算機概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "電子工程"}'::jsonb, NULL),
